def check_permission(user, action, resource):
    if user.user_id == resource.owner_id:
        return True
    if action == 'delete' and user.role not in ('admin', 'manager'):
        return False
    if user.role == 'viewer':
        return action == 'view'
    if user.role == 'editor':
        return action in ('view', 'edit')
    if user.role == 'manager':
        return action in ('view', 'edit', 'admin')
    if user.role == 'admin':
        return True
    return False
